/*
 * initpath - Perform all necessary initialization of the search path,
 *  which may be simply saving the path.
 *
 * Requires:
 *   "pathstr" is a valid search path.
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
initpath(const char *pathstr)
{
	char *path, *delim, *p;
	int npaths_local = 0;

	// Handle NULL or empty path string
	if (pathstr == NULL || strlen(pathstr) == 0) {
		patharray[npaths_local++] = ".";
		npaths = npaths_local;
		return;
	}

	// Make a copy since we'll be modifying it
	path = malloc(strlen(pathstr) + 1);
	if (path == NULL) {
		unix_error("malloc error");
	}
	strcpy(path, pathstr);

	// Parse the path string
	p = path;
	while (*p != '\0') {
		delim = strchr(p, ':');
		if (delim == NULL) {
			// Last component
			if (*p == '\0' || npaths_local >= 127) {
				break;
			}
			patharray[npaths_local++] = p;
			break;
		}

		// Check for empty component (:: or :at start)
		if (p == delim) {
			patharray[npaths_local++] = ".";
		} else {
			*delim = '\0';
			patharray[npaths_local++] = p;
		}

		p = delim + 1;
	}

	// Check if path ends with ':' (empty component at end)
	if (strlen(pathstr) > 0 && pathstr[strlen(pathstr) - 1] == ':') {
		if (npaths_local < 127) {
			patharray[npaths_local++] = ".";
		}
	}

	patharray[npaths_local] = NULL;
	npaths = npaths_local;
}

/*
 * search_path - Search for an executable in the PATH.
 *
 * Returns a dynamically allocated argv array with the full path
 * to the executable, or NULL if not found.
 */
static char **
search_path(const char *filename)
{
	static char fullpath[MAXLINE];
	char **argv;
	int i;

	// If filename contains '/', use it as-is
	if (strchr(filename, '/') != NULL) {
		argv = malloc(2 * sizeof(char *));
		if (argv == NULL)
			return (NULL);
		argv[0] = malloc(strlen(filename) + 1);
		if (argv[0] == NULL)
			return (NULL);
		strcpy(argv[0], filename);
		argv[1] = NULL;
		return (argv);
	}

	// Search through PATH directories
	for (i = 0; i < npaths && patharray[i] != NULL; i++) {
		snprintf(fullpath, MAXLINE, "%s/%s", patharray[i], filename);
		if (access(fullpath, X_OK) == 0) {
			argv = malloc(2 * sizeof(char *));
			if (argv == NULL)
				return (NULL);
			argv[0] = malloc(strlen(fullpath) + 1);
			if (argv[0] == NULL)
				return (NULL);
			strcpy(argv[0], fullpath);
			argv[1] = NULL;
			return (argv);
		}
	}

	return (NULL);
}

