		// Search for the executable and get the full path
		fullargv = search_path(argv[0]);
		if (fullargv != NULL) {
			// Use the full path
			strcpy(fullpath, fullargv[0]);
			free(fullargv[0]);
			free(fullargv);
		} else {
			// Use the original name (let execve fail if it doesn't exist)
			strcpy(fullpath, argv[0]);
		}

		// Execute the program with the original argv (argv[0] is the program name)
		if (execve(fullpath, argv, environ) < 0) {
			printf("%s: Command not found\n", argv[0]);
			exit(1);
		}
	}

	// Parent process:
