static void
do_bgfg(char **argv)
{
	struct Job *job;
	char *id;
	int jid;
	pid_t pid;
	long val;
	char *endptr;

	// Check if we have an argument
	if (argv[1] == NULL) {
		printf("%s command requires %%jobid or jobpid argument\n", argv[0]);
		return;
	}

	id = argv[1];

	// Parse the job ID or PID
	if (id[0] == '%') {
		// It's a JID
		jid = strtol(&id[1], &endptr, 10);
		if (*endptr != '\0' || jid <= 0) {
			printf("%s: argument must be a PID or %%jobid\n", argv[0]);
			return;
		}
		job = (struct Job *)getjobjid(jobs, jid);
		if (job == NULL) {
			printf("%s: No such job\n", id);
			return;
		}
	} else {
		// It's a PID
		val = strtol(id, &endptr, 10);
		if (*endptr != '\0' || val <= 0) {
			printf("%s: argument must be a PID or %%jobid\n", argv[0]);
			return;
		}
		pid = (pid_t)val;
		job = (struct Job *)getjobpid(jobs, pid);
		if (job == NULL) {
			printf("(%d): No such process\n", (int)pid);
			return;
		}
	}

	// Send SIGCONT to the process group
	if (kill(-job->pid, SIGCONT) < 0) {
		unix_error("kill (SIGCONT) error");
	}

	// Update the job state
	if (strcmp(argv[0], "bg") == 0) {
		job->state = BG;
		printf("[%d] (%d) %s", job->jid, (int)job->pid, job->cmdline);
	} else {
		job->state = FG;
		waitfg(job->pid);
	}
}

