/*
 * eval - Evaluate the command line that the user has just typed in.
 *
 * If the user has requested a built-in command (quit, jobs, bg or fg)
 * then execute it immediately.  Otherwise, fork a child process and
 * run the job in the context of the child.  If the job is running in
 * the foreground, wait for it to terminate and then return.  Note:
 * each child process must have a unique process group ID so that our
 * background children don't receive SIGINT (SIGTSTP) from the kernel
 * when we type ctrl-c (ctrl-z) at the keyboard.
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
eval(const char *cmdline)
{
	char *argv[MAXARGS];
	char buf[MAXLINE];
	bool bg;
	pid_t pid;
	sigset_t mask, prev_mask;
	char **fullargv;

	// Copy the command line to avoid modifying the original
	strcpy(buf, cmdline);

	// Parse the command line
	bg = parseline(buf, argv);

	// If there are no arguments, return
	if (argv[0] == NULL)
		return;

	// Check if it's a built-in command
	if (builtin_cmd(argv))
		return;

	// Prepare to fork: block SIGCHLD before forking
	sigemptyset(&mask);
	sigaddset(&mask, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask, &prev_mask);

	// Fork the child process
	if ((pid = fork()) == 0) {
		// Child process:
		// Restore the signal mask for the child
		sigprocmask(SIG_SETMASK, &prev_mask, NULL);

		// Set up a new process group
		if (setpgid(0, 0) < 0)
			unix_error("setpgid error");

		// Search for the executable and get the full path
		fullargv = search_path(argv[0]);
		if (fullargv != NULL) {
			// Use the full path (argv[0] is the program name/path)
			argv[0] = fullargv[0];
		}

		// Execute the program
		if (execve(argv[0], argv, environ) < 0) {
			printf("%s: Command not found\n", argv[0]);
			exit(1);
		}
	}

	// Parent process:
	// Add the job to the job list
	if (bg) {
		addjob(jobs, pid, BG, cmdline);
		sigprocmask(SIG_SETMASK, &prev_mask, NULL);
		printf("[%d] (%d) %s", pid2jid(pid), (int)pid, cmdline);
	} else {
		addjob(jobs, pid, FG, cmdline);
		sigprocmask(SIG_SETMASK, &prev_mask, NULL);
		waitfg(pid);
	}
}

