if (pid == 0) {
	// Child process:
	// Restore the signal mask for the child
	sigprocmask(SIG_SETMASK, &prev_mask, NULL);

	// Set up a new process group
	if (setpgid(0, 0) < 0)
		unix_error("setpgid error");

	// Try to execute the program directly first
	execve(argv[0], argv, environ);

	// If execve fails and the command doesn't contain '/',
	// try searching in PATH
	if (strchr(argv[0], '/') == NULL) {
		char **fullargv = search_path(argv[0]);
		if (fullargv != NULL) {
